/* File: static/src/css/stock_checker.css */
/* Purpose: Complete styling for the Stock Enhanced Checker OWL dashboard */

/* ═══════════════════════════════════════════════════════════════
   CSS Variables / Design Tokens
   ═══════════════════════════════════════════════════════════════ */
:root {
    --sc-primary: #4f46e5;
    --sc-primary-light: #6366f1;
    --sc-primary-dark: #3730a3;
    --sc-accent: #06b6d4;
    --sc-success: #10b981;
    --sc-warning: #f59e0b;
    --sc-danger: #ef4444;
    --sc-bg: #0f172a;
    --sc-bg-card: #1e293b;
    --sc-bg-card2: #243047;
    --sc-bg-hover: #2d3f5c;
    --sc-bg-selected: rgba(79, 70, 229, 0.15);
    --sc-border: rgba(255, 255, 255, 0.08);
    --sc-text: #e2e8f0;
    --sc-text-muted: #94a3b8;
    --sc-text-dim: #64748b;
    --sc-radius: 12px;
    --sc-radius-sm: 8px;
    --sc-shadow: 0 4px 24px rgba(0, 0, 0, 0.35);
    --sc-shadow-lg: 0 8px 40px rgba(0, 0, 0, 0.5);
    --sc-glass: rgba(30, 41, 59, 0.85);
    --sc-transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
}

/* ═══════════════════════════════════════════════════════════════
   Light Theme Overrides
   ═══════════════════════════════════════════════════════════════ */
.o_stock_checker_app.sc-theme-light {
    --sc-bg: #f1f5f9;
    --sc-bg-card: #ffffff;
    --sc-bg-card2: #f8fafc;
    --sc-bg-hover: #e8edf4;
    --sc-bg-selected: rgba(79, 70, 229, 0.08);
    --sc-border: rgba(0, 0, 0, 0.1);
    --sc-text: #1e293b;
    --sc-text-muted: #475569;
    --sc-text-dim: #94a3b8;
    --sc-shadow: 0 4px 24px rgba(0, 0, 0, 0.08);
    --sc-shadow-lg: 0 8px 40px rgba(0, 0, 0, 0.12);
    --sc-glass: rgba(255, 255, 255, 0.9);
}

.sc-theme-light .sc-header {
    background: linear-gradient(135deg, #ffffff 0%, #f1f5f9 100%);
}

.sc-theme-light .sc-header-brand {
    background: linear-gradient(135deg, #4f46e5, #06b6d4);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

.sc-theme-light .sc-select option {
    background: #fff;
    color: #1e293b;
}

.sc-theme-light .sc-table thead th {
    background: #f8fafc;
}

.sc-theme-light .sc-table tbody td {
    border-bottom-color: rgba(0, 0, 0, 0.06);
}

.sc-theme-light .sc-product-name {
    color: #3730a3;
}

.sc-theme-light .sc-product-ref {
    color: #64748b;
}

.sc-theme-light .sc-qty-input {
    background: rgba(241, 245, 249, 0.8);
    color: #1e293b;
}

.sc-theme-light .sc-qty-input:focus {
    background: #fff;
}

.sc-theme-light .sc-uom-badge {
    background: rgba(79, 70, 229, 0.1);
    color: #4f46e5;
}

.sc-theme-light .sc-stat-chip {
    background: rgba(0, 0, 0, 0.04);
}

.sc-theme-light .sc-partner-input {
    background: #f1f5f9;
    color: #1e293b;
}

.sc-theme-light .sc-partner-input:hover,
.sc-theme-light .sc-partner-input:focus {
    background: #fff;
}

.sc-theme-light .sc-partner-dropdown {
    background: #fff;
}

.sc-theme-light .sc-partner-ref {
    background: rgba(79, 70, 229, 0.1);
    color: #4f46e5;
}

.sc-theme-light .sc-incoming-tooltip:hover::after {
    background: #fff;
}

/* Theme toggle button */
.sc-theme-toggle {
    background: var(--sc-bg-card2);
    border: 1px solid var(--sc-border);
    border-radius: var(--sc-radius-sm);
    color: var(--sc-text-muted);
    width: 32px;
    height: 32px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    transition: var(--sc-transition);
    font-size: 14px;
    flex-shrink: 0;
    padding: 0;
}

.sc-theme-toggle:hover {
    border-color: var(--sc-primary-light);
    color: var(--sc-text);
    background: var(--sc-bg-hover);
}

/* ═══════════════════════════════════════════════════════════════
   Root Container
   ═══════════════════════════════════════════════════════════════ */
.o_stock_checker_app {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: var(--sc-bg);
    color: var(--sc-text);
    font-family: 'Inter', 'Segoe UI', system-ui, sans-serif;
    overflow: hidden;
}

/* ═══════════════════════════════════════════════════════════════
   Header Bar
   ═══════════════════════════════════════════════════════════════ */
.sc-header {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 8px 16px;
    background: linear-gradient(135deg, #1e293b 0%, #0f172a 100%);
    border-bottom: 1px solid var(--sc-border);
    flex-wrap: wrap;
    box-shadow: 0 2px 8px rgba(0,0,0,0.25);
    z-index: 10;
    position: relative;
    min-height: 48px;
}

.sc-header-brand {
    font-size: 0.95rem;
    font-weight: 700;
    background: linear-gradient(135deg, #818cf8, #06b6d4);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    white-space: nowrap;
    flex-shrink: 0;
}

.sc-controls {
    display: flex;
    align-items: center;
    gap: 12px;
    flex-wrap: wrap;
    flex: 1;
}

/* Vertical divider between control groups */
.sc-header-divider {
    width: 1px;
    height: 20px;
    background: var(--sc-border);
    flex-shrink: 0;
    margin: 0 2px;
}

/* Partner input wrapper when placed inside the header */
.sc-header-partner {
    min-width: 150px;
    max-width: 200px;
    flex: 1;
}

/* ═══════════════════════════════════════════════════════════════
   Selects & Inputs
   ═══════════════════════════════════════════════════════════════ */
.sc-select,
.sc-search-input {
    background: var(--sc-bg-card);
    border: 1px solid var(--sc-border);
    border-radius: var(--sc-radius-sm);
    color: var(--sc-text);
    padding: 5px 10px;
    font-size: 0.8125rem;
    transition: var(--sc-transition);
    outline: none;
    height: 32px;
}

.sc-select {
    min-width: 140px;
    cursor: pointer;
}

.sc-select:hover,
.sc-search-input:hover {
    border-color: var(--sc-primary-light);
    background: var(--sc-bg-card2);
}

.sc-select:focus,
.sc-search-input:focus {
    border-color: var(--sc-primary);
    box-shadow: 0 0 0 3px rgba(79, 70, 229, 0.2);
}

.sc-select option {
    background: var(--sc-bg-card);
    color: var(--sc-text);
}

.sc-search-wrapper {
    position: relative;
    flex: 1;
    min-width: 200px;
    max-width: 360px;
}

.sc-search-wrapper .sc-search-icon {
    position: absolute;
    left: 10px;
    top: 50%;
    transform: translateY(-50%);
    color: var(--sc-text-dim);
    font-size: 14px;
    pointer-events: none;
}

.sc-search-input {
    width: 100%;
    padding-left: 32px;
}

/* ═══════════════════════════════════════════════════════════════
   Filter Pills
   ═══════════════════════════════════════════════════════════════ */
.sc-filters {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 6px 16px;
    background: var(--sc-bg-card);
    border-bottom: 1px solid var(--sc-border);
    flex-wrap: wrap;
    min-height: 38px;
}

.sc-filter-label {
    font-size: 0.7rem;
    color: var(--sc-text-dim);
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    margin-right: 2px;
    flex-shrink: 0;
}

.sc-filter-btn {
    background: transparent;
    border: 1px solid var(--sc-border);
    border-radius: 20px;
