}

/* Right side: count + buttons */
.sc-action-right {
    display: flex;
    align-items: center;
    gap: 10px;
    flex-shrink: 0;
}

.sc-selection-info {
    font-size: 0.875rem;
    color: var(--sc-text-muted);
    display: flex;
    align-items: center;
