    align-items: center;
    justify-content: center;
    background: var(--sc-primary);
    color: #fff;
    border-radius: 20px;
    padding: 2px 10px;
    font-size: 0.8rem;
    font-weight: 700;
    min-width: 28px;
    box-shadow: 0 2px 6px rgba(79, 70, 229, 0.4);
