}

.sc-action-buttons {
    display: flex;
    align-items: center;
    gap: 10px;
}

/* Load More */
.sc-load-more-wrapper {
    text-align: center;
    padding: 12px;
}

/* ═══════════════════════════════════════════════════════════════
   Buttons
   ═══════════════════════════════════════════════════════════════ */
.sc-btn {
