    align-items: center;
    gap: 7px;
    border: none;
    border-radius: var(--sc-radius-sm);
    font-size: 0.875rem;
    font-weight: 600;
    cursor: pointer;
    padding: 9px 20px;
    transition: var(--sc-transition);
    white-space: nowrap;
    text-decoration: none;
}

.sc-btn:disabled {
    opacity: 0.45;
    cursor: not-allowed;
    transform: none !important;
    box-shadow: none !important;
}

.sc-btn-primary {
    background: linear-gradient(135deg, var(--sc-primary), var(--sc-primary-light));
    color: #fff;
    box-shadow: 0 2px 12px rgba(79, 70, 229, 0.4);
}

.sc-btn-primary:not(:disabled):hover {
    transform: translateY(-1px);
    box-shadow: 0 4px 20px rgba(79, 70, 229, 0.55);
    background: linear-gradient(135deg, var(--sc-primary-light), var(--sc-primary));
}

.sc-btn-primary:not(:disabled):active {
    transform: translateY(0);
}

.sc-btn-secondary {
    background: var(--sc-bg-card2);
    color: var(--sc-text-muted);
    border: 1px solid var(--sc-border);
}

.sc-btn-secondary:not(:disabled):hover {
    background: var(--sc-bg-hover);
    color: var(--sc-text);
    border-color: var(--sc-primary-light);
}

.sc-btn-outline {
    background: transparent;
    color: var(--sc-primary-light);
    border: 1px solid var(--sc-primary);
}

.sc-btn-outline:not(:disabled):hover {
    background: rgba(79, 70, 229, 0.12);
