    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 16px;
    padding: 60px 24px;
    color: var(--sc-text-dim);
}

.sc-spinner {
    width: 40px;
    height: 40px;
    border: 3px solid var(--sc-border);
    border-top-color: var(--sc-primary);
    border-radius: 50%;
    animation: sc-spin 0.8s linear infinite;
}

@keyframes sc-spin {
    to { transform: rotate(360deg); }
}

.sc-loading-text {
    font-size: 0.9rem;
    font-weight: 500;
    color: var(--sc-text-dim);
}

/* ═══════════════════════════════════════════════════════════════
   Empty State
   ═══════════════════════════════════════════════════════════════ */
.sc-empty {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 12px;
    padding: 60px 24px;
    color: var(--sc-text-dim);
}

.sc-empty-icon {
    font-size: 48px;
    opacity: 0.3;
}

.sc-empty h3 {
    font-size: 1.1rem;
    font-weight: 600;
    color: var(--sc-text-muted);
    margin: 0;
}

.sc-empty p {
    font-size: 0.875rem;
    margin: 0;
    text-align: center;
}

/* ═══════════════════════════════════════════════════════════════
   Toast Notification
   ═══════════════════════════════════════════════════════════════ */
.sc-toast {
    position: fixed;
    bottom: 30px;
    right: 30px;
    background: var(--sc-bg-card2);
    border: 1px solid var(--sc-border);
    border-radius: var(--sc-radius);
    padding: 14px 20px;
    display: flex;
    align-items: center;
    gap: 12px;
    box-shadow: var(--sc-shadow-lg);
    z-index: 9999;
    max-width: 380px;
    animation: sc-toast-in 0.35s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
}

.sc-toast.sc-toast-success { border-left: 4px solid var(--sc-success); }
.sc-toast.sc-toast-error   { border-left: 4px solid var(--sc-danger); }
.sc-toast.sc-toast-info    { border-left: 4px solid var(--sc-accent); }

.sc-toast-icon {
    font-size: 20px;
    flex-shrink: 0;
}

.sc-toast-success .sc-toast-icon { color: var(--sc-success); }
.sc-toast-error   .sc-toast-icon { color: var(--sc-danger); }
.sc-toast-info    .sc-toast-icon { color: var(--sc-accent); }

.sc-toast-body {
    flex: 1;
}

.sc-toast-title {
    font-weight: 700;
    font-size: 0.9rem;
    color: var(--sc-text);
}

.sc-toast-msg {
    font-size: 0.82rem;
    color: var(--sc-text-muted);
    margin-top: 2px;
}

.sc-toast-close {
    background: none;
    border: none;
    color: var(--sc-text-dim);
    cursor: pointer;
    font-size: 16px;
    line-height: 1;
    padding: 2px;
    transition: var(--sc-transition);
}

.sc-toast-close:hover { color: var(--sc-text); }

@keyframes sc-toast-in {
    from { opacity: 0; transform: translateX(60px) scale(0.9); }
    to   { opacity: 1; transform: translateX(0) scale(1); }
}

.sc-toast.sc-toast-out {
    animation: sc-toast-out 0.25s ease forwards;
}

@keyframes sc-toast-out {
    to { opacity: 0; transform: translateX(60px) scale(0.9); }
}

/* Icon-only button */
.sc-btn-icon {
    padding: 5px 10px;
    min-width: 32px;
}

/* ═══════════════════════════════════════════════════════════════
   Stat Chips (inline in filter bar)
   ═══════════════════════════════════════════════════════════════ */
.sc-stat-chip {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: rgba(255,255,255,0.05);
    border: 1px solid var(--sc-border);
    border-radius: 20px;
    padding: 2px 10px;
    font-size: 0.75rem;
    color: var(--sc-text-muted);
    white-space: nowrap;
    flex-shrink: 0;
}

.sc-stat-chip strong {
    font-weight: 700;
    color: var(--sc-text);
}

.sc-chip-success strong { color: var(--sc-success); }
.sc-chip-warning strong { color: var(--sc-warning); }
.sc-chip-danger  strong { color: var(--sc-danger); }
.sc-chip-accent  strong { color: var(--sc-accent); }

/* ═══════════════════════════════════════════════════════════════
   Responsive
   ═══════════════════════════════════════════════════════════════ */
@media (max-width: 768px) {
    .sc-header { padding: 12px 16px; gap: 10px; }
    .sc-table-container { padding: 0 12px 12px; }
    .sc-action-bar { padding: 12px 16px; }
    .sc-filters { padding: 8px 16px; }
    .sc-stats-bar { padding: 8px 16px; }

    /* Hide internal ref on small screens */
    .sc-col-ref { display: none; }
    .sc-col-reorder { display: none; }
