/* File: static/src/css/stock_checker.css */
/* Purpose: Minimal, clean design for Stock Enhanced Checker */

/* ═══════════════════════════════════════════════════════════════
   Design Tokens — Dark (default)
   ═══════════════════════════════════════════════════════════════ */
:root {
    --sc-primary: #6366f1;
    --sc-primary-hover: #818cf8;
    --sc-primary-soft: rgba(99, 102, 241, 0.12);
    --sc-accent: #06b6d4;
    --sc-success: #34d399;
    --sc-success-soft: rgba(52, 211, 153, 0.12);
    --sc-warning: #fbbf24;
    --sc-warning-soft: rgba(251, 191, 36, 0.12);
    --sc-danger: #f87171;
    --sc-danger-soft: rgba(248, 113, 113, 0.12);

    --sc-surface-0: #0f172a;
    --sc-surface-1: #1e293b;
    --sc-surface-2: #273549;
    --sc-surface-3: #334155;
    --sc-hover: rgba(255, 255, 255, 0.04);
    --sc-selected: rgba(99, 102, 241, 0.10);
    --sc-border: rgba(255, 255, 255, 0.07);

    --sc-text: #f1f5f9;
    --sc-text-secondary: #94a3b8;
    --sc-text-muted: #64748b;

    --sc-radius: 10px;
    --sc-radius-sm: 6px;
    --sc-radius-full: 9999px;
    --sc-shadow: 0 1px 3px rgba(0, 0, 0, 0.3);
    --sc-transition: 0.15s ease;
}

/* ═══════════════════════════════════════════════════════════════
   Light Theme
   ═══════════════════════════════════════════════════════════════ */
.o_stock_checker_app.sc-theme-light {
    --sc-primary: #4f46e5;
    --sc-primary-hover: #6366f1;
    --sc-primary-soft: rgba(79, 70, 229, 0.08);
    --sc-accent: #0891b2;
    --sc-success: #16a34a;
    --sc-success-soft: rgba(22, 163, 74, 0.08);
    --sc-warning: #d97706;
    --sc-warning-soft: rgba(217, 119, 6, 0.08);
    --sc-danger: #dc2626;
    --sc-danger-soft: rgba(220, 38, 38, 0.08);

    --sc-surface-0: #f8fafc;
    --sc-surface-1: #ffffff;
    --sc-surface-2: #f1f5f9;
    --sc-surface-3: #e2e8f0;
    --sc-hover: rgba(0, 0, 0, 0.03);
    --sc-selected: rgba(79, 70, 229, 0.06);
    --sc-border: rgba(0, 0, 0, 0.08);

    --sc-text: #0f172a;
    --sc-text-secondary: #475569;
    --sc-text-muted: #94a3b8;
}

/* ═══════════════════════════════════════════════════════════════
   Root
   ═══════════════════════════════════════════════════════════════ */
.o_stock_checker_app {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: var(--sc-surface-0);
    color: var(--sc-text);
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
    font-size: 14px;
    line-height: 1.5;
    overflow: hidden;
}

/* ═══════════════════════════════════════════════════════════════
   Header — single clean row
   ═══════════════════════════════════════════════════════════════ */
.sc-header {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 12px;
    background: var(--sc-surface-1);
    border-bottom: 1px solid var(--sc-border);
    flex-shrink: 0;
}

.sc-header-brand {
    font-size: 15px;
    font-weight: 700;
    color: var(--sc-primary);
    white-space: nowrap;
    margin-right: 4px;
    flex-shrink: 0;
}

.sc-controls {
    display: flex;
    align-items: center;
    gap: 8px;
    flex: 1;
    min-width: 0;
}

/* ═══════════════════════════════════════════════════════════════
   Inputs & Selects
   ═══════════════════════════════════════════════════════════════ */
.sc-select {
    background: var(--sc-surface-2);
    border: 1px solid var(--sc-border);
    border-radius: var(--sc-radius-sm);
    color: var(--sc-text);
    padding: 5px 28px 5px 10px;
    font-size: 13px;
    height: 32px;
    outline: none;
    cursor: pointer;
    transition: border-color var(--sc-transition);
    appearance: auto;
    min-width: 120px;
    max-width: 180px;
    flex-shrink: 0;
}

.sc-select:focus {
    border-color: var(--sc-primary);
}

.sc-select option {
    background: var(--sc-surface-1);
    color: var(--sc-text);
}

/* Search */
.sc-search-wrap {
    position: relative;
    flex: 1;
    min-width: 160px;
    max-width: 320px;
}

.sc-search-wrap i {
    position: absolute;
    left: 10px;
    top: 50%;
    transform: translateY(-50%);
    color: var(--sc-text-muted);
    font-size: 13px;
    pointer-events: none;
}

.sc-search-input {
    width: 100%;
    background: var(--sc-surface-2);
    border: 1px solid var(--sc-border);
    border-radius: var(--sc-radius-sm);
    color: var(--sc-text);
    padding: 5px 10px 5px 30px;
    font-size: 13px;
    height: 32px;
    outline: none;
    transition: border-color var(--sc-transition);
}

.sc-search-input:focus {
    border-color: var(--sc-primary);
}

.sc-search-input::placeholder {
    color: var(--sc-text-muted);
}

/* Icon buttons */
.sc-icon-btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 32px;
    height: 32px;
    border: 1px solid var(--sc-border);
    border-radius: var(--sc-radius-sm);
    background: var(--sc-surface-2);
    color: var(--sc-text-secondary);
    cursor: pointer;
    flex-shrink: 0;
    transition: all var(--sc-transition);
    padding: 0;
}

.sc-icon-btn:hover {
    border-color: var(--sc-primary);
    color: var(--sc-primary);
}

/* ═══════════════════════════════════════════════════════════════
   Filter Bar
   ═══════════════════════════════════════════════════════════════ */
.sc-filter-bar {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 6px 12px;
    background: var(--sc-surface-0);
    border-bottom: 1px solid var(--sc-border);
    flex-shrink: 0;
    overflow-x: auto;
}

.sc-filter-pill {
    display: inline-flex;
    align-items: center;
    gap: 5px;
    border: 1px solid var(--sc-border);
    border-radius: var(--sc-radius-full);
    background: transparent;
    color: var(--sc-text-secondary);
    padding: 4px 12px;
    font-size: 12.5px;
    font-weight: 500;
    cursor: pointer;
    white-space: nowrap;
    transition: all var(--sc-transition);
}

.sc-filter-pill:hover {
    border-color: var(--sc-primary);
    color: var(--sc-text);
}

.sc-filter-pill.active {
    background: var(--sc-primary);
    border-color: var(--sc-primary);
    color: #fff;
}

.sc-filter-pill i {
    font-size: 11px;
}

.sc-filter-spacer {
    flex: 1;
}

/* Stat badges — small inline numbers */
.sc-stat {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    font-size: 12px;
    color: var(--sc-text-muted);
    white-space: nowrap;
}

.sc-stat b {
    font-weight: 600;
}

.sc-stat-ok b { color: var(--sc-success); }
.sc-stat-warn b { color: var(--sc-warning); }
.sc-stat-bad b { color: var(--sc-danger); }
.sc-stat-in b { color: var(--sc-accent); }

