    padding: 4px 8px;
    font-size: 13px;
    text-align: right;
    outline: none;
    font-variant-numeric: tabular-nums;
    transition: border-color var(--sc-transition);
}

.sc-input-sm:focus {
    border-color: var(--sc-primary);
}

.sc-input-price {
    width: 84px;
}

/* Select-all row */
.sc-select-all-row {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 6px 14px;
    margin-bottom: 6px;
    font-size: 12px;
    color: var(--sc-text-muted);
}

.sc-select-all-row label {
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 6px;
}

/* ═══════════════════════════════════════════════════════════════
   Bottom Action Bar
   ═══════════════════════════════════════════════════════════════ */
