.sc-partner-group {
    display: flex;
    align-items: center;
    gap: 8px;
    flex: 1;
    min-width: 0;
}

.sc-partner-wrap {
    position: relative;
    min-width: 140px;
    max-width: 200px;
    flex: 1;
}

.sc-partner-input {
    width: 100%;
    background: var(--sc-surface-2);
    border: 1px solid var(--sc-border);
    border-radius: var(--sc-radius-sm);
    color: var(--sc-text);
    padding: 5px 10px 5px 28px;
    font-size: 13px;
    height: 32px;
    outline: none;
    transition: border-color var(--sc-transition);
}

.sc-partner-input:focus {
    border-color: var(--sc-primary);
}

.sc-partner-input::placeholder {
    color: var(--sc-text-muted);
}

.sc-partner-input.sc-input-new {
    border-color: var(--sc-accent);
}

.sc-partner-wrap i {
    position: absolute;
    left: 9px;
    top: 50%;
    transform: translateY(-50%);
    color: var(--sc-text-muted);
    font-size: 12px;
    pointer-events: none;
}

/* Partner badge */
.sc-p-badge {
    position: absolute;
    right: 6px;
    top: 50%;
    transform: translateY(-50%);
    font-size: 10px;
    font-weight: 700;
    border-radius: 8px;
    padding: 0 6px;
    pointer-events: none;
    line-height: 18px;
}

.sc-p-badge-existing {
    background: var(--sc-success-soft);
    color: var(--sc-success);
}

.sc-p-badge-new {
    background: rgba(6, 182, 212, 0.12);
    color: var(--sc-accent);
}

/* Partner dropdown */
.sc-partner-dd {
    position: absolute;
    top: calc(100% + 4px);
    left: 0;
    right: 0;
    background: var(--sc-surface-1);
    border: 1px solid var(--sc-primary);
    border-radius: var(--sc-radius-sm);
    z-index: 200;
    box-shadow: var(--sc-shadow);
    overflow: hidden;
    animation: sc-dd-in 0.12s ease;
}

@keyframes sc-dd-in {
    from { opacity: 0; transform: translateY(-4px); }
    to   { opacity: 1; transform: translateY(0); }
}

.sc-partner-dd-item {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 7px 10px;
    cursor: pointer;
    font-size: 13px;
    color: var(--sc-text-secondary);
    transition: background 0.1s;
}

.sc-partner-dd-item:hover {
    background: var(--sc-primary-soft);
    color: var(--sc-text);
}

.sc-partner-dd-ref {
    font-size: 11px;
    font-weight: 600;
    color: var(--sc-primary);
    font-family: 'SF Mono', monospace;
}

/* Selection count */
.sc-sel-count {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    background: var(--sc-primary);
    color: #fff;
    border-radius: var(--sc-radius-full);
    padding: 2px 10px;
    font-size: 12px;
    font-weight: 700;
    min-width: 26px;
}

.sc-sel-label {
    font-size: 13px;
    color: var(--sc-text-muted);
    white-space: nowrap;
}

.sc-action-spacer {
    flex: 1;
}

/* Buttons */
.sc-btn {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    border: none;
    border-radius: var(--sc-radius-sm);
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
    padding: 7px 16px;
    white-space: nowrap;
    transition: all var(--sc-transition);
}

.sc-btn:disabled {
    opacity: 0.4;
    cursor: not-allowed;
}

.sc-btn-primary {
    background: var(--sc-primary);
    color: #fff;
}

.sc-btn-primary:not(:disabled):hover {
    background: var(--sc-primary-hover);
}

.sc-btn-ghost {
    background: transparent;
    color: var(--sc-text-secondary);
    border: 1px solid var(--sc-border);
}

.sc-btn-ghost:not(:disabled):hover {
    background: var(--sc-hover);
    border-color: var(--sc-primary);
    color: var(--sc-text);
}

.sc-btn-outline {
    background: transparent;
    color: var(--sc-primary);
    border: 1px solid var(--sc-primary);
}

.sc-btn-outline:not(:disabled):hover {
    background: var(--sc-primary-soft);
}

/* Load more */
.sc-load-more {
    text-align: center;
    padding: 12px;
}

/* ═══════════════════════════════════════════════════════════════
   Loading
   ═══════════════════════════════════════════════════════════════ */
.sc-loading {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 14px;
    padding: 60px 20px;
}

.sc-spinner {
    width: 32px;
    height: 32px;
    border: 2.5px solid var(--sc-border);
    border-top-color: var(--sc-primary);
    border-radius: 50%;
    animation: sc-spin 0.7s linear infinite;
}

@keyframes sc-spin { to { transform: rotate(360deg); } }

.sc-loading-text {
    font-size: 13px;
    color: var(--sc-text-muted);
}

/* ═══════════════════════════════════════════════════════════════
   Empty State
   ═══════════════════════════════════════════════════════════════ */
.sc-empty {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 10px;
    padding: 60px 20px;
}

.sc-empty-icon {
    font-size: 40px;
    opacity: 0.25;
}

.sc-empty h3 {
    font-size: 15px;
    font-weight: 600;
    color: var(--sc-text-secondary);
    margin: 0;
}

.sc-empty p {
    font-size: 13px;
    color: var(--sc-text-muted);
    margin: 0;
}

/* ═══════════════════════════════════════════════════════════════
   Toast
   ═══════════════════════════════════════════════════════════════ */
.sc-toast {
    position: fixed;
    bottom: 20px;
    right: 20px;
    background: var(--sc-surface-1);
    border: 1px solid var(--sc-border);
    border-radius: var(--sc-radius);
    padding: 12px 16px;
    display: flex;
    align-items: center;
    gap: 10px;
    box-shadow: var(--sc-shadow);
    z-index: 9999;
    max-width: 360px;
    animation: sc-toast-in 0.3s ease forwards;
}

.sc-toast-success { border-left: 3px solid var(--sc-success); }
.sc-toast-error   { border-left: 3px solid var(--sc-danger); }
.sc-toast-info    { border-left: 3px solid var(--sc-accent); }

.sc-toast-icon { font-size: 18px; flex-shrink: 0; }
.sc-toast-success .sc-toast-icon { color: var(--sc-success); }
.sc-toast-error   .sc-toast-icon { color: var(--sc-danger); }
.sc-toast-info    .sc-toast-icon { color: var(--sc-accent); }

.sc-toast-body { flex: 1; }

.sc-toast-title {
    font-weight: 600;
    font-size: 13px;
    color: var(--sc-text);
}

.sc-toast-msg {
    font-size: 12px;
    color: var(--sc-text-muted);
    margin-top: 2px;
}

.sc-toast-close {
    background: none;
    border: none;
    color: var(--sc-text-muted);
    cursor: pointer;
    font-size: 14px;
    padding: 2px;
}

@keyframes sc-toast-in {
    from { opacity: 0; transform: translateY(20px); }
    to   { opacity: 1; transform: translateY(0); }
}

/* ═══════════════════════════════════════════════════════════════
   Responsive
   ═══════════════════════════════════════════════════════════════ */
@media (max-width: 768px) {
    .sc-header {
        flex-wrap: wrap;
    }
    .sc-search-wrap {
        max-width: none;
        order: 10;
        width: 100%;
    }
    .sc-card-meta {
        gap: 6px;
    }
    .sc-card-ref {
        display: none;
    }
    .sc-partner-group {
        flex-wrap: wrap;
    }
    .sc-partner-wrap {
        max-width: none;
    }
}

